import { saveSoChiTietPageSession, reportPageSessionKey } from '../components/report/reportPageSessionCache';
import { KT } from '../router/paths';
import type { LedgerEntryDto } from '../services/kt/models';
import { openWorkspaceTab } from './openWorkspaceTab';

export type OpenSoChiTietFromSoCaiInput = {
  row: LedgerEntryDto;
  accountCode: string;
  accountName: string;
  fromDate?: string;
  returnPath: string;
  returnTitle: string;
  detailReportTitle: string;
  navigate: (path: string) => void;
};

/** Sổ cái row menu → Sổ chi tiết (prefill tháng/năm từ dòng + TK từ filter). */
export function openSoChiTietFromSoCaiRow(input: OpenSoChiTietFromSoCaiInput): void {
  const {
    row,
    accountCode,
    accountName,
    fromDate,
    returnPath,
    returnTitle,
    detailReportTitle,
    navigate,
  } = input;

  let month: string;
  let year: string;
  const entry = new Date(row.entryDate);
  if (!Number.isNaN(entry.getTime())) {
    month = String(entry.getMonth() + 1);
    year = String(entry.getFullYear());
  } else if (fromDate) {
    const filterDate = new Date(fromDate);
    month = String(filterDate.getMonth() + 1);
    year = String(filterDate.getFullYear());
  } else {
    const now = new Date();
    month = String(now.getMonth() + 1);
    year = String(now.getFullYear());
  }

  const detailPath = KT.SO_CHI_TIET;
  saveSoChiTietPageSession(reportPageSessionKey(detailPath, ''), {
    month,
    year,
    accountCode,
    accountName,
    items: [],
  });

  openWorkspaceTab(
    {
      path: detailPath,
      title: detailReportTitle,
      returnPath,
      returnTitle,
    },
    navigate,
  );
}
